fn main() -> i64 = {
    let n: i64 = read_int();
    let m: i64 = read_int();

    // Create adjacency list (vector of vectors)
    let adj: i64 = vec_new();
    for i in 0..n {
        vec_push(adj, vec_new());
        ()
    };

    // In-degree array
    let indegree: i64 = vec_new();
    for i in 0..n {
        vec_push(indegree, 0);
        ()
    };

    // Read edges
    for i in 0..m {
        let u: i64 = read_int();
        let v: i64 = read_int();
        let adj_u: i64 = vec_get(adj, u);
        vec_push(adj_u, v);
        let old_deg: i64 = vec_get(indegree, v);
        vec_set(indegree, v, old_deg + 1);
        ()
    };

    // Queue for BFS (Kahn's algorithm)
    let queue: i64 = vec_new();

    // Add all nodes with indegree 0
    for i in 0..n {
        if vec_get(indegree, i) == 0 {
            vec_push(queue, i);
            ()
        } else { () };
        ()
    };

    // Result array
    let result: i64 = vec_new();

    // Process queue
    let mut front: i64 = 0;
    while front < vec_len(queue) {
        let u: i64 = vec_get(queue, front);
        front = front + 1;
        vec_push(result, u);

        let adj_u: i64 = vec_get(adj, u);
        let num_neighbors: i64 = vec_len(adj_u);
        for j in 0..num_neighbors {
            let v: i64 = vec_get(adj_u, j);
            let new_deg: i64 = vec_get(indegree, v) - 1;
            vec_set(indegree, v, new_deg);
            if new_deg == 0 {
                vec_push(queue, v);
                ()
            } else { () };
            ()
        };
        ()
    };

    // Print result
    let result_len: i64 = vec_len(result);
    for i in 0..result_len {
        if i > 0 {
            print_str(" ");
            ()
        } else { () };
        print(vec_get(result, i));
        ()
    };
    println_str("");

    // Free memory
    for i in 0..n {
        vec_free(vec_get(adj, i));
        ()
    };
    vec_free(adj);
    vec_free(indegree);
    vec_free(queue);
    vec_free(result);

    0
};
